"""Batch 12 : 38 avis FR Tier 1 finaux (clôture du Tier 1)."""
import json

PATH = 'data/avis_annuel.json'

AVIS_BATCH12_FR = {
    "alsace:fr": "L'Alsace, c'est la région française la plus germanique : 600 km² entre Vosges et Forêt-Noire, 1,9 million d'habitants, vignobles, villages à colombages, gastronomie de tradition alémanique. <strong>Juillet est mon mois préféré</strong> (8.8/10) : 16-26°C, 38% de pluie, terrasses de Strasbourg et Colmar, randonnées dans les Vosges. <strong>D'août</strong> reste excellent (8.6/10) avec moins de touristes après le 15. <strong>De novembre à mars</strong>, comptez 0-12°C et 39-44% de pluie : froid sec continental, neige dans les Vosges (ski possible au Champ du Feu, La Bresse). Mais c'est l'apogée touristique avec les <strong>marchés de Noël</strong> (Strasbourg, Colmar, Riquewihr, Kaysersberg) du dernier vendredi de novembre au 24 décembre = parmi les plus anciens et plus visités d'Europe, prix x2-x3, foules massives. <strong>Sites majeurs</strong> : <strong>Route des Vins</strong> (170 km de Marlenheim à Thann, 70 villages, Riesling/Gewurztraminer/Pinot Gris), villages classés <strong>Plus Beaux de France</strong> : Eguisheim (origine de la vigne), Riquewihr, Hunawihr, Kaysersberg. <strong>Strasbourg</strong> (UNESCO, voir avis dédié), <strong>Colmar</strong> (Petite Venise, Musée Unterlinden avec Retable d'Issenheim), <strong>Mont Sainte-Odile</strong> (panorama plaine d'Alsace). <strong>Tester</strong> choucroute (chez Gilg à Riquewihr ou Le Picotin à Strasbourg), tarte flambée (\"flammkueche\"), baeckeoffe, kougelhopf, bredele, vins d'Alsace. Mai-juin et septembre-octobre sont les meilleurs compromis tourisme/météo.",

    "bretagne:fr": "La Bretagne, péninsule de l'extrême ouest français : 27 000 km², 3,3 millions d'habitants, 2700 km de côtes, identité celtique forte (langue bretonne, fest-noz, musique). <strong>Juillet-août sont mes mois préférés</strong> (8.5-8.6/10) : 14-24°C, 28-30% de pluie, pic touristique. <strong>De juin à septembre</strong>, comptez 13-23°C avec 30-39% de pluie : haute saison ; météo capricieuse mais souvent agréable. <strong>De novembre à mars</strong>, comptez 3-13°C et 38-45% de pluie : océanique humide, ciel souvent gris, mais moins violente que la Côte d'Émeraude en hiver (légende des tempêtes bretonnes). <strong>Sites majeurs</strong> : <strong>Côte de Granit Rose</strong> (Perros-Guirec, Ploumanac'h, Trégastel - rochers roses, sentier des Douaniers), <strong>Côte d'Émeraude</strong> (Saint-Malo intra-muros, Cap Fréhel, Dinan), <strong>Côte Sauvage</strong> à Quiberon, <strong>Belle-Île-en-Mer</strong> en bateau (45 min, Aiguilles de Port-Coton peintes par Monet), <strong>Pointe du Raz</strong> et <strong>Pointe du Van</strong> (extrême ouest), <strong>Carnac</strong> (3000 menhirs alignés, plus grand site mégalithique au monde), <strong>Vannes</strong> et <strong>Golfe du Morbihan</strong> (40 îles), <strong>Brest</strong> et <strong>Forêt de Brocéliande</strong> (légendes arthuriennes). <strong>Festivals</strong> : Fest-noz (UNESCO, fêtes nocturnes traditionnelles), Festival Interceltique de Lorient (août), Vieilles Charrues à Carhaix (juillet, l'un des plus grands festivals français). <strong>Tester</strong> galettes/crêpes (sarrasin/froment), kouign-amann, far breton, cidre, chouchen, fruits de mer (huîtres de Cancale).",

    "bruges:fr": "Bruges, en Flandre belge : 120 000 habitants, classée UNESCO, surnommée la \"Venise du Nord\" pour ses 50 km de canaux. Ville préservée du Moyen Âge (faillite économique XVe l'a paradoxalement épargnée). <strong>Août est mon mois préféré</strong> (8.2/10) : 15-22°C, 39% de pluie, terrasses sur les canaux. <strong>De juillet à septembre</strong>, c'est la haute saison : 13-22°C avec 35-39% de pluie, mais foules très denses (Bruges concentre 8 millions de visiteurs/an pour 120 000 habitants), réservation hôtels 2-3 mois avant. <strong>De novembre à février</strong>, comptez 2-9°C et 43-49% de pluie : doux pour la Belgique, marchés de Noël sur Markt et Minnewater, ambiance \"In Bruges\" (film de Martin McDonagh 2008 a popularisé la ville). <strong>Sites majeurs</strong> : <strong>Markt</strong> (place principale, Beffroi 83m, 366 marches pour la vue), <strong>Burg</strong> (Hôtel de Ville gothique, Basilique du Saint-Sang), <strong>Béguinage</strong> (UNESCO, calme religieux), <strong>Lac d'Amour (Minnewater)</strong>, <strong>Grand'Place</strong>, <strong>Musée Groeninge</strong> (primitifs flamands, Van Eyck, Memling), <strong>Choco-Story</strong> et <strong>Frietmuseum</strong>. <strong>Croisière en barque sur les canaux</strong> (30 min, 12€) = quasi obligatoire pour saisir l'âme de la ville. <strong>Tester</strong> moules-frites, waterzooi, frites belges, gaufres de Bruges (différentes des liégeoises), chocolat (chez Dumon, Sukerbuyc), bière (3 sœurs : Brugse Zot, Straffe Hendrik, Tripel Karmeliet). À 1h en train de Bruxelles. Mai-juin et octobre sont les meilleurs compromis foule/météo.",

    "bruxelles:fr": "Bruxelles, capitale belge et de l'Union européenne : 1,2 million d'habitants en aire urbaine, ville bilingue français/néerlandais, mosaïque culturelle (1/3 des résidents sont étrangers). <strong>Juillet-août sont mes mois préférés</strong> (8.3/10) : 14-23°C, 35-36% de pluie, terrasses, Bruxelles-les-Bains (plage urbaine sur le canal mi-juillet à mi-août). <strong>De novembre à février</strong>, comptez 2-10°C et 42-45% de pluie : doux pour l'Europe du Nord, marché de Noël <strong>Plaisirs d'Hiver</strong> mi-novembre à début janvier (Grand-Place, Place Sainte-Catherine, Marché aux Poissons). <strong>D'avril à juin</strong>, comptez 5-22°C : printemps souvent pluvieux mais agréable. <strong>Sites majeurs</strong> : <strong>Grand-Place</strong> (UNESCO, l'une des plus belles places au monde, Hôtel de Ville XVe, Maisons des Corporations XVIIe), <strong>Manneken Pis</strong> (60 cm, déçoit toujours par sa petitesse), <strong>Atomium</strong> (102m, ouvert pour Expo 1958, ascenseur dans la sphère centrale), <strong>Cathédrale Saints-Michel-et-Gudule</strong>, <strong>Quartier Sablon</strong> (antiquaires, chocolatiers), <strong>Quartier européen</strong> (Parlement européen visitable), <strong>Mont des Arts</strong>. <strong>Musées</strong> : <strong>Magritte</strong> (le plus surréaliste), <strong>Royaux des Beaux-Arts</strong>, <strong>Musée de la BD</strong> (Tintin, Schtroumpfs, Astérix), <strong>Horta Museum</strong> (Art Nouveau). <strong>Tester</strong> moules-frites (chez Léon depuis 1893), waterzooi, carbonade flamande, frites (Maison Antoine), gaufres de Liège, chocolat (Pierre Marcolini, Neuhaus, Godiva), bière trappiste (Westvleteren, Chimay, Orval).",

    "canaries:fr": "Les Canaries, archipel espagnol au large du Maroc : 7 îles principales, 2,2 millions d'habitants, climat subtropical le plus stable d'Europe (\"l'éternel printemps\"). <strong>Juillet est mon mois préféré</strong> (9.7/10) : 20-28°C, 0% de pluie. <strong>Toute l'année</strong> est praticable : 14-29°C en moyenne, mer à 19-24°C, alizés constants, hors zone cyclonique. <strong>De juillet à octobre</strong>, c'est la pleine haute saison : 19-29°C, 0-7% de pluie. <strong>De décembre à mars</strong>, comptez 14-22°C : haute saison hivernale (Européens du Nord en hivernage, snowbirds), prix x2 dans les resorts. <strong>7 îles à connaître</strong> : <strong>Tenerife</strong> (la plus grande, Teide 3718m point culminant d'Espagne), <strong>Gran Canaria</strong> (Maspalomas dunes), <strong>Lanzarote</strong> (paysages volcaniques noirs, Timanfaya, César Manrique), <strong>Fuerteventura</strong> (les plus belles plages, kite/surf), <strong>La Palma</strong> (\"isla bonita\", randonnée), <strong>La Gomera</strong> (forêt laurifère, sifflement silbo), <strong>El Hierro</strong> (la plus petite, plongée). <strong>Sites majeurs</strong> : <strong>Teide National Park</strong> (UNESCO, paysages martiens, ascension Pico del Teide en téléphérique + permis spécial pour le sommet), <strong>Maspalomas</strong> (dunes au bord de la mer), <strong>Timanfaya</strong> (volcan toujours brûlant, démonstrations de chaleur géothermique), <strong>Garajonay</strong> (UNESCO, forêt laurifère préhistorique). <strong>Cuisine</strong> : papas arrugadas con mojo (rouge piquant ou vert), gofio, vieja (poisson local), sancocho. <strong>Vols directs depuis Paris</strong> vers Tenerife/Gran Canaria/Lanzarote en 4h30.",

    "cape-cod:fr": "Cape Cod, c'est la péninsule en forme de bras au sud-est de Boston, Massachusetts : 105 km de long, 350 000 habitants permanents (multipliés par 3 en été), villas victoriennes en bardeaux, plages atlantiques, phares historiques. <strong>Juillet est mon mois préféré</strong> (8.8/10) : 20-26°C, 31% de pluie, mer à 21°C (encore fraîche), ferries vers les îles. <strong>D'août</strong> reste excellent (8.7/10). <strong>De juin à septembre</strong>, c'est la haute saison touristique américaine : prix hôteliers x3-x4, réservations 6 mois avant pour les inns charmants (Chatham Bars Inn, Wequassett). <strong>De décembre à mars</strong>, comptez -2/7°C et 35-39% de précipitations souvent neige : 60% des restos et hôtels ferment, mais ambiance hivernale calme. <strong>Sites majeurs</strong> : <strong>Provincetown</strong> (P-Town, à la pointe nord, ambiance LGBT depuis les 70s, ferries vers Boston), <strong>Cape Cod National Seashore</strong> (60 km de plages atlantiques sauvages), <strong>Cape Cod Rail Trail</strong> (40 km de piste cyclable sur ancienne voie ferrée), <strong>Phares</strong> (Highland Light, Nauset Light, Chatham Light). <strong>Iles à découvrir en ferry</strong> : <strong>Martha's Vineyard</strong> (45 min depuis Falmouth, ex-villégiature des Kennedy et Obama, Edgartown chic), <strong>Nantucket</strong> (1h15 ou avion 30 min depuis Hyannis, ambiance baleinière XIXe préservée). <strong>Whale watching</strong> depuis Provincetown (fin mai à octobre). <strong>Tester</strong> lobster roll (chez Mac's Seafood), clam chowder, fried clams (Whole Belly chez Kream 'N' Kone), oysters de Wellfleet. À 2h de Boston en voiture.",

    "charleston:fr": "Charleston, en Caroline du Sud : 150 000 habitants, ville coloniale anglaise (1670), centre historique préservé, rôle majeur dans l'esclavage et la guerre de Sécession. Régulièrement classée parmi les plus belles villes des USA. <strong>Mai est mon mois préféré</strong> (8.7/10) : 20-27°C, 38% de pluie, fin du printemps avec azalées et magnolias en pleine floraison. <strong>Avril-juin</strong> sont la haute saison touristique : 16-29°C, 24-54% de pluie. <strong>De juin à septembre</strong>, c'est la saison cyclonique (côte est USA) : 38-64% de précipitations, taux d'humidité oppressant (Charleston peut atteindre des records de chaleur ressentie). <strong>De décembre à février</strong>, comptez 6-17°C et 28-32% de pluie : doux pour le sud, faible affluence touristique. <strong>Octobre-novembre</strong> sont mes vrais bons compromis : 11-25°C, ciel dégagé après la saison cyclonique. <strong>Sites majeurs</strong> : <strong>Vieille ville</strong> (200 maisons coloniales avant 1860 préservées, plus que toute autre ville US), <strong>Battery Park</strong> et <strong>Rainbow Row</strong> (maisons colorées, photo signature), <strong>Old Slave Mart Museum</strong> (ex-marché aux esclaves, mémorial), <strong>Fort Sumter</strong> (premier coup de feu de la guerre de Sécession en 1861, ferry depuis Liberty Square), <strong>Magnolia Plantation et Drayton Hall</strong> (anciennes plantations à 30 min, sujet sensible mais éducatif), <strong>Boone Hall Plantation</strong> (allée de chênes centenaires utilisée dans Le Patriot et Forrest Gump). <strong>Tester</strong> shrimp and grits (plat Lowcountry), she-crab soup, fried green tomatoes, sweet tea. À 1h de Hilton Head Island. Vol direct depuis NY/DC/Boston.",

    "denver:fr": "Denver, capitale du Colorado : 700 000 habitants, surnommée la \"Mile-High City\" car à 1609m d'altitude exactement (ligne marquée au Capitole). Base pour explorer les Rocheuses américaines. <strong>Juin est mon mois préféré</strong> (9.3/10) : 13-29°C, 22% de pluie, températures idéales avant la chaleur estivale. <strong>De septembre à octobre</strong>, comptez 4-28°C : foliage spectaculaire (peupliers dorés \"aspens\" mi-septembre à mi-octobre, plus belle saison de l'Ouest américain). <strong>De décembre à mars</strong>, comptez -8/12°C et 12-27% de précipitations souvent neige : c'est la saison ski (Denver est la base aérienne pour Aspen, Vail, Breckenridge, Keystone, Copper Mountain - toutes à 1h30-3h30 en voiture). <strong>D'avril à mai</strong>, comptez -2/21°C : variabilité météo extrême (neige possible jusqu'en mai). <strong>Sites majeurs</strong> : <strong>Capitole</strong> (le Mile High Step gravé), <strong>Larimer Square</strong> (premier quartier de Denver), <strong>Union Station</strong> (réhabilitée 2014), <strong>Denver Art Museum</strong> (architecture Daniel Libeskind), <strong>Red Rocks Amphitheatre</strong> à 30 min (lieu de concert dans des roches rouges, U2 y a tourné Under a Blood Red Sky en 1983), <strong>Coors Brewery</strong> à Golden (la plus grande brasserie au monde sur un seul site), <strong>16th Street Mall</strong>. <strong>Excursions</strong> : <strong>Rocky Mountain National Park</strong> à 1h30 (Trail Ridge Road, plus haute route paved des USA, Estes Park base), <strong>Garden of the Gods</strong> à 1h30 (Colorado Springs), <strong>Pikes Peak</strong> 4302m. <strong>Tester</strong> green chile (cuisine du sud-ouest), Rocky Mountain oysters (testicules de taureau panés, défi local), bières craft (Denver = capitale US de la bière artisanale, 100+ brasseries).",

    "dordogne:fr": "La Dordogne (département + rivière), c'est le cœur du Périgord : 9000 km², 410 000 habitants, châteaux médiévaux, grottes préhistoriques, gastronomie de truffe et foie gras. <strong>Juillet-août sont mes mois préférés</strong> (9.2/10) : 17-28°C, 22-24% de pluie, températures idéales, feuilletages d'or des cygnes sur les rivières. <strong>De juin à septembre</strong>, c'est la haute saison : 14-28°C, prix hôteliers x2, location maisons de campagne très demandées (Britanniques nombreux). <strong>De décembre à février</strong>, comptez 3-12°C et 41-43% de pluie : doux pour la France, bonne période pour la <strong>truffe noire du Périgord</strong> (saison décembre-février, marchés à Sarlat/Sorges/Lalbenque). <strong>Sites majeurs</strong> : <strong>Sarlat-la-Canéda</strong> (cité médiévale exceptionnelle, marchés du mercredi/samedi), <strong>Vallée de la Vézère</strong> (UNESCO, sites préhistoriques) : <strong>Lascaux IV</strong> (réplique, l'original fermé depuis 1963 pour préservation), <strong>Les Eyzies</strong> (Musée National de la Préhistoire), <strong>Font-de-Gaume</strong> et <strong>Combarelles</strong> (rares grottes encore visitables avec art préhistorique original), <strong>Vallée de la Dordogne</strong> avec ses villages perchés (<strong>Domme</strong>, <strong>La Roque-Gageac</strong>, <strong>Beynac</strong>, <strong>Castelnaud</strong>). <strong>Châteaux</strong> : Beynac, Castelnaud (rivaux médiévaux), Hautefort, Bourdeilles, Biron. <strong>Activités</strong> : descente de la Dordogne en canoë (Vitrac à La Roque-Gageac, 12 km, 25-35€/personne). <strong>Marché de Sarlat</strong> samedi matin. <strong>Tester</strong> foie gras, magret/confit de canard, truffe noire, noix, fraises, vin de Bergerac/Monbazillac, vin de Cahors voisin.",

    "dubrovnik:fr": "Dubrovnik, la \"Perle de l'Adriatique\" : 40 000 habitants, ville fortifiée UNESCO, 1900 km de remparts conservés. Popularisée par <strong>Game of Thrones</strong> (Port-Réal tourné ici depuis 2011, multiplication des touristes par 5). <strong>Juin est mon mois préféré</strong> (9.3/10) : 19-28°C, 24% de pluie, mer à 23°C, températures idéales avant la chaleur étouffante. <strong>Juillet-août chutent à 6.9/10</strong> à cause de la chaleur (21-30°C) et surtout de la <strong>foule extrême</strong> : 1,4 million de touristes/an, 4-6 paquebots de croisière par jour qui débarquent 10 000 visiteurs simultanément, ville fortifiée saturée, prix x4-x5. La mairie limite désormais à 4000 visiteurs simultanés dans la vieille ville (compteurs aux portes). <strong>De novembre à mars</strong>, comptez 3-15°C et 31-51% de pluie : doux mais beaucoup d'hôtels et restos ferment. <strong>Sites majeurs</strong> : <strong>Stradun</strong> (artère principale en marbre poli par les pas), <strong>Remparts</strong> (tour 2 km à pied, 35€ entrée, prendre tôt 8h ou tard 17h pour éviter foule et chaleur), <strong>Palais des Recteurs</strong>, <strong>Cathédrale</strong>, <strong>Mont Srđ</strong> (téléphérique pour la vue panoramique au coucher du soleil), <strong>Île de Lokrum</strong> en ferry 15 min (parc naturel, Iron Throne pour les fans GoT). <strong>Excursions</strong> : <strong>Kotor</strong> (Monténégro) à 2h (UNESCO, baie spectaculaire), <strong>îles Élaphites</strong> (Lopud, Šipan), <strong>Mostar</strong> (Bosnie, à 3h, Stari Most), <strong>Korčula</strong> et <strong>Hvar</strong> en ferry. <strong>Tester</strong> peka (viande/poulpe cuit sous cloche), pasticada (boeuf en sauce), rožata (flan local), vin Dingač (rouge local).",

    "edimbourg:fr": "Édimbourg, capitale écossaise : 540 000 habitants, vieille ville médiévale (UNESCO) sur volcan éteint, ville géorgienne XVIIIe (UNESCO également = double inscription rare). <strong>Juillet-septembre sont mes mois préférés</strong> (7.0-7.2/10) : 8-18°C, 46-53% de pluie, c'est la saison des festivals d'août (<strong>Edinburgh Festival Fringe</strong>, le plus grand festival d'arts vivants au monde, 3000 spectacles sur 25 jours, et le Edinburgh International Festival, plus traditionnel). Prix hôteliers x4-x5 en août, réservation 6 mois avant. <strong>De décembre à mars</strong>, comptez 2-9°C et 42-52% de pluie : froid humide, jours à 7h de lumière fin décembre, mais <strong>Hogmanay</strong> (réveillon écossais, 30 décembre-1er janvier, l'une des plus grandes fêtes du Nouvel An au monde, défilé de torches, feux d'artifice, ceilidhs - bals folkloriques). <strong>Sites majeurs</strong> : <strong>Royal Mile</strong> (1,8 km de la Vieille Ville, du Château au Holyrood Palace), <strong>Château d'Édimbourg</strong> (sur Castle Rock, perché à 130m, joyaux de la couronne d'Écosse), <strong>Holyrood Palace</strong> (résidence officielle de la famille royale en Écosse), <strong>Arthur's Seat</strong> (251m, ancien volcan en plein centre, randonnée 1h pour la vue), <strong>Calton Hill</strong> (panoramique alternatif), <strong>National Museum of Scotland</strong>, <strong>Dean Village</strong> (charmant dans le centre). <strong>Greyfriars Bobby</strong> (statue d'un terrier qui a veillé 14 ans la tombe de son maître, légende locale). <strong>Excursions</strong> : <strong>Stirling Castle</strong> à 1h, <strong>Loch Lomond</strong> et les Highlands à 2h, <strong>île de Skye</strong> à 5-6h. <strong>Tester</strong> haggis (panse de brebis farcie, plat national), neeps and tatties, cranachan, single malt whisky.",

    "guadeloupe:fr": "La Guadeloupe, département français d'outre-mer aux Petites Antilles : 1700 km², 380 000 habitants, archipel en forme de papillon (Basse-Terre montagneuse à l'ouest + Grande-Terre plus plate à l'est). <strong>Janvier est mon mois préféré</strong> (8.3/10) : 23-28°C, 50% de pluie, mer à 27°C, c'est le carême (saison sèche). <strong>De décembre à avril</strong>, c'est la haute saison touristique : 23-29°C, 50-59% de précipitations en averses brèves, prix hôteliers x2-x3 (vol depuis Paris x3 en pleine saison). <strong>De juillet à octobre</strong>, c'est la saison cyclonique active (\"hivernage\") : 65-83% de précipitations, risque ouragans réel (Maria 2017 a causé des dégâts importants), mais températures stables (24-31°C). <strong>De mai-juin et novembre</strong> sont les meilleures intersaisons : prix réduits, foule modérée. <strong>Sites majeurs côté Basse-Terre</strong> (volcan, jungle, randonnées) : <strong>La Soufrière</strong> (1467m, randonnée 1h30 au sommet, soufre actif, fumeroles), <strong>Cascades du Carbet</strong>, <strong>Plage de Grande Anse</strong> à Deshaies, <strong>Plage de la Perle</strong>, <strong>Réserve Cousteau</strong> (plongée et snorkeling). <strong>Sites majeurs côté Grande-Terre</strong> (plages, plus touristique) : <strong>Pointe-à-Pitre</strong> (capitale, marché St-Antoine), <strong>Sainte-Anne</strong> (plage de la Caravelle), <strong>Saint-François</strong> (port de plaisance, golf), <strong>Pointe des Châteaux</strong> (extrême est, falaises calcaires). <strong>Iles voisines</strong> : <strong>Marie-Galante</strong> (\"l'île aux 100 moulins\"), <strong>Les Saintes</strong> (Terre-de-Haut, plus belle baie du monde selon UNESCO), <strong>La Désirade</strong>. <strong>Tester</strong> bokit, accras, colombo, ti-punch, sorbet coco, rhum Damoiseau et Bologne. Vol direct Paris en 8h.",

    "hallstatt:fr": "Hallstatt, village autrichien de 800 habitants au bord du <strong>Hallstättersee</strong> : classé UNESCO en 1997 pour son patrimoine de mines de sel pré-romaines (active depuis 7000 ans, l'une des plus anciennes au monde). Décor de carte postale alpestre (montagnes, lac, clochers), surfréquenté depuis 2010 (10 000 visiteurs/jour en été pour 800 habitants). <strong>Août est mon mois préféré</strong> (7.9/10) : 15-25°C, 59% de pluie en orages d'altitude, températures clémentes. <strong>De juillet à septembre</strong>, c'est la haute saison : 12-24°C, mais <strong>foules extrêmes</strong> (le \"Hallstatt Selfie Spot\" sur la promenade lacustre est saturé, foules de touristes asiatiques en bus depuis Salzbourg ou Vienne). La municipalité a installé des barrières en 2023 pour gérer le flux. <strong>De décembre à mars</strong>, comptez -2/8°C et 43-55% de précipitations souvent neige : Hallstatt sous la neige est <strong>spectaculaire</strong>, avec ski en proximité (Dachstein-West à 10 min, Krippenstein), beaucoup moins de touristes (sauf weekends). <strong>Sites majeurs</strong> : <strong>Marktplatz</strong> (place principale), <strong>Église protestante</strong> (clocher signature avec le lac en arrière-plan), <strong>Salzwelten</strong> (mines de sel les plus anciennes au monde, accessible par funiculaire depuis le village + petit train dans les galeries, panorama 5 lacs depuis le World Heritage Skywalk au sommet 350m au-dessus du lac), <strong>Eis Riesenwelt</strong> à 1h (la plus grande grotte de glace au monde, à Werfen, ouvert mai-octobre). <strong>Logistique</strong> : Hallstatt à 1h15 de Salzbourg en voiture (parking obligatoire avant le village, accès piéton seulement), train Hallstatt-Markt + ferry 10 min depuis la gare. <strong>Tester</strong> Wiener Schnitzel, fromages locaux. Compter 1 nuit minimum pour profiter de l'ambiance hors heures de tour-opérateurs.",

    "hvar:fr": "Hvar, île chic et festive de Croatie : 70 km de long, 11 000 habitants, lavande et romarin, soleil le plus stable de l'Adriatique (2724h/an, record). <strong>Juin est mon mois préféré</strong> (9.6/10) : 21-28°C, 15% de pluie, mer à 23°C, lavande en pleine floraison (juin-juillet). <strong>Juillet-août chutent à 6.9/10</strong> à cause de la chaleur (23-31°C) et de la <strong>foule extrême</strong> : Hvar Town est devenue depuis 2010 une destination party (Carpe Diem, Hula Hula, Falko), prix hôteliers x4-x5, port saturé de yachts (parmi les plus chic d'Europe avec Saint-Tropez et Mykonos). <strong>De novembre à mars</strong>, comptez 7-15°C et 34-43% de pluie : 80% des hôtels et restos ferment, ferries réduits. <strong>Sites majeurs</strong> : <strong>Hvar Town</strong> (citadelle Fortica au sommet, cathédrale Saint-Étienne, place principale Pjaca - la plus grande de Dalmatie), <strong>Stari Grad</strong> (UNESCO, Plaine de Stari Grad, paysages agricoles antiques préservés depuis les Grecs), <strong>Jelsa</strong> et <strong>Vrboska</strong> (\"Petite Venise\", canaux), <strong>champs de lavande</strong> autour de Velo Grablje (juin-juillet). <strong>Iles Pakleni</strong> en bateau-taxi 15 min (Sveti Klement, Marinkovac, Jerolim avec plage Stipanska : restaurant tendance Carpe Diem Beach). <strong>Plages</strong> : Dubovica (sud, criquette splendide), Pokonji Dol, Mlini. <strong>Brač</strong> en ferry voisin (plage Zlatni Rat, fameux fer à cheval qui change de forme avec les courants). <strong>Tester</strong> peka (sous cloche), gregada (poisson aux pommes de terre), pršut (jambon dalmate), vin Plavac Mali. Aéroport le plus proche : Split (1h en ferry) ou Brač (été). Mai et septembre-octobre = meilleurs compromis.",

    "key-west:fr": "Key West, l'extrémité sud des Florida Keys : 25 000 habitants à 150 km de Cuba (l'\"USA continental\" le plus au sud, marqueur Mile 0 sur la US-1). Île bohème, ambiance Caraïbe, héritage Hemingway. <strong>Avril est mon mois préféré</strong> (9.0/10) : 24-26°C, 23% de pluie, mer à 26°C, fin de la saison touristique américaine. <strong>De décembre à avril</strong>, c'est la haute saison : 20-26°C, 14-25% de pluie, prix hôteliers x2-x4, Spring Break américain de mars (foules étudiantes débridées). <strong>De juin à octobre</strong>, c'est la saison cyclonique : 53-65% de précipitations, risque ouragans (Irma 2017 catégorie 4 a touché les Keys). <strong>De mai et novembre</strong> sont les meilleures intersaisons. <strong>Sites majeurs</strong> : <strong>Mallory Square</strong> au coucher du soleil (\"Sunset Celebration\" rituel quotidien depuis les 60s, jongleurs, magiciens, applaudissements au moment où le soleil se couche dans le golfe), <strong>Hemingway House</strong> (l'écrivain a vécu ici 1931-1939, écrit Pour qui sonne le glas, descendants de ses chats à 6 doigts), <strong>Southernmost Point</strong> (bouée signalant l'\"USA continental\" le plus sud, photo obligatoire), <strong>Duval Street</strong> (rue principale, bars, restos, ambiance touristique mais incontournable), <strong>Conch Train Tour</strong> (petit train touristique 90 min). <strong>Activités</strong> : <strong>Dry Tortugas National Park</strong> (Fort Jefferson, accès en hydravion ou ferry 2h30, journée complète), snorkeling/plongée sur la barrière corallienne (3e plus grande au monde), pêche en haute mer. <strong>Conduite Miami-Key West</strong> par l'<strong>Overseas Highway</strong> (250 km de pont sur la mer, Seven Mile Bridge mythique) = expérience en soi (3-4h). <strong>Tester</strong> Key Lime Pie (origine ici), conch fritters, fish sandwich.",

    "kotor:fr": "Kotor, ville fortifiée du Monténégro : 14 000 habitants au fond de la <strong>Bouches de Kotor</strong> (UNESCO 1979), fjord méditerranéen le plus au sud d'Europe. Comparable à Dubrovnik mais moins fréquentée et moins chère. <strong>Juin est mon mois préféré</strong> (9.1/10) : 20-27°C, 27% de pluie, mer à 23°C, lumière dorée sur les remparts. <strong>Juillet-août chutent à 6.9/10</strong> à cause de la chaleur (23-30°C) et de la <strong>foule de croisière</strong> (la baie reçoit 4-6 paquebots par jour, ville saturée 10h-17h). <strong>De novembre à mars</strong>, comptez 6-15°C et 34-48% de pluie : doux mais humide, beaucoup d'hôtels ferment. <strong>D'avril-mai et septembre-octobre</strong> sont les meilleurs compromis. <strong>Sites majeurs</strong> : <strong>Vieille ville fortifiée</strong> (UNESCO, dédale de ruelles médiévales, Cathédrale Saint-Tryphon XIIe), <strong>Forteresse Saint-Jean</strong> (1350 marches sur la falaise pour 280m de dénivelé, vue panoramique exceptionnelle sur la baie, à monter tôt le matin avant la chaleur, 8€), <strong>Place des Armes</strong>, <strong>Tour de l'Horloge</strong>. <strong>Excursions baie de Kotor</strong> : <strong>Perast</strong> (ville baroque vénitienne, 12 palais XVIIe), <strong>Notre-Dame du Rocher</strong> (île artificielle créée par les pêcheurs depuis 1452, accessible en barque), <strong>Risan</strong> (mosaïques romaines), <strong>Boka Bay tour</strong> en bateau (3-4h, baignade dans grotte bleue). <strong>Excursions Monténégro</strong> : <strong>Lovćen National Park</strong> (mausolée de Petar II Petrović-Njegoš au sommet, 461 marches), <strong>Budva</strong> à 30 min (station balnéaire), <strong>Sveti Stefan</strong> (île-hôtel 5*, photo signature). <strong>Tester</strong> njeguški pršut (jambon fumé), kačamak, raki monténégrin. Aéroport le plus proche : Tivat (10 min) ou Podgorica (1h30).",

    "lac-garde:fr": "Le lac de Garde (\"Lago di Garda\"), le plus grand lac d'Italie : 370 km², 158 km de tour, en forme de Y inversé entre Vénétie/Lombardie/Trentin. Plus accessible et moins jet-set que le lac de Côme, plus familial et sportif. <strong>Juin-août sont mes mois préférés</strong> (8.6-8.8/10) : 14-29°C, 36-37% de pluie, baignade dans le lac (eau à 24°C en plein été), windsurf et kitesurf (vent constant Pelér du nord matin et Ora du sud après-midi). <strong>De novembre à mars</strong>, comptez 3-14°C et 24-36% de pluie : doux pour l'Italie du Nord, citronniers de Limone toujours verts, ski possible à 30 min (Monte Baldo, Madonna di Campiglio, Folgaria). <strong>Régions</strong> : <strong>Sud</strong> (Sirmione, Desenzano, Peschiera) plat, plus chaud, plus animé, accès facile depuis Vérone/Milan ; <strong>Nord</strong> (Riva del Garda, Limone sul Garda) montagneux, alpin, sports de glisse, lac plus étroit (effet fjord). <strong>Sites majeurs</strong> : <strong>Sirmione</strong> (péninsule fortifiée scaligère, sources thermales, Grottes de Catulle = ruines romaines), <strong>Riva del Garda</strong> (côté Trentin), <strong>Limone sul Garda</strong> (citronneraies, ses limonaie = serres en pierres), <strong>Malcesine</strong> (téléphérique pour Monte Baldo 1760m), <strong>Bardolino</strong> (vins rouges), <strong>Desenzano</strong> (port animé). <strong>Gardaland</strong> (le plus grand parc d'attractions d'Italie, à Castelnuovo del Garda). <strong>Activités</strong> : voile, planche à voile, kitesurf à Torbole, randonnée Monte Baldo, vélo route du lac. <strong>Tester</strong> tortelli di zucca (raviolis de courge), risotto al tastasal (saucisse), bigoli, vin Bardolino/Lugana, huile d'olive du lac.",

    "laponie:fr": "La Laponie, c'est la région circumpolaire qui couvre le nord de la Finlande, Suède, Norvège et Russie. La plus accessible touristiquement : <strong>Laponie finlandaise</strong> autour de Rovaniemi (capitale). <strong>Juillet est mon mois préféré</strong> (7.6/10) : 11-18°C, 46% de pluie, c'est le \"jour sans fin\" (soleil de minuit, pas de coucher du soleil pendant 73 jours à Rovaniemi), randonnées, lacs et taïga. <strong>De juin à août</strong>, comptez 6-18°C : haute saison estivale (peu de moustiques en juin, beaucoup en juillet-août). <strong>De novembre à mars</strong>, comptez -12/-2°C et 32-41% de précipitations souvent neige : c'est la haute saison touristique pour les <strong>aurores boréales</strong> (visibles 200 nuits/an quand le ciel est dégagé, meilleures probabilités septembre-mars), prix x3-x5 en décembre (Père Noël), nuits qui durent 24h en plein hiver. <strong>Activités hivernales</strong> : <strong>aurores boréales</strong> (chasse en motoneige ou tente lavvu, fenêtre 21h-2h), <strong>traîneau à chiens husky</strong> (initiation 1h, mushing 2-7 jours), <strong>traîneau à rennes Sami</strong> (peuple indigène, plus paisible), <strong>safari motoneige</strong>, <strong>ski de fond</strong>, <strong>pêche sur glace</strong>, <strong>nuit en igloo de verre</strong> (Kakslauttanen, Wilderness Hotel à Inari, 400-1000€/nuit). <strong>Sites majeurs</strong> : <strong>Rovaniemi</strong> (\"Capitale Officielle du Père Noël\", Santa Claus Village au cercle polaire, lettre du Père Noël expédiée du bureau officiel), <strong>Levi</strong> (station ski avec vie), <strong>Saariselka</strong> et <strong>Inari</strong> (Lac Inari, capitale culturelle Sami). <strong>Tester</strong> renne (en pâté Poronkäristys), saumon fumé sur le feu (loimulohi), baies (chicouté/cloudberry).",

    "lofoten:fr": "Les îles Lofoten, archipel norvégien au-delà du cercle polaire : 7 îles principales reliées par ponts, 24 000 habitants, paysages les plus spectaculaires de Norvège (montagnes 1000m qui plongent dans la mer, villages de pêcheurs colorés). <strong>Juillet est mon mois préféré</strong> (7.5/10) : 11-16°C, 44% de pluie, c'est le \"soleil de minuit\" (du 28 mai au 14 juillet, pas de coucher du soleil pendant 7 semaines), randonnées, kayak, pêche. <strong>De juin à août</strong>, comptez 8-16°C : haute saison estivale (peu de touristes hors croisières), <strong>Reine</strong> et <strong>Hamnøy</strong> sont les villages les plus photographiés (bondés en juillet). <strong>De septembre à mars</strong>, comptez -5/7°C et 47-61% de précipitations souvent neige : c'est la saison des <strong>aurores boréales</strong> (Lofoten = l'un des meilleurs spots au monde, visible dès qu'il fait nuit ET ciel dégagé, ce qui est rare en hiver lofoten), pêche au cabillaud (skrei) en mars (l'or de la mer norvégienne, pêche traditionnelle continue depuis 1000 ans). <strong>De décembre à janvier</strong>, c'est la <strong>nuit polaire</strong> (Pas de soleil au-dessus de l'horizon pendant 4 semaines, mais lumière bleue magnifique). <strong>Sites majeurs</strong> : <strong>Reine</strong> (le village le plus iconique, photo signature depuis Reinebringen 448m, 1500 marches en bois rénovées 2018), <strong>Hamnøy</strong> et ses rorbuer rouges (cabanes de pêcheurs sur pilotis), <strong>Henningsvær</strong> (\"Venise des Lofoten\", pont depuis 1981), <strong>Plage de Kvalvika</strong> (randonnée 1h, sable blanc), <strong>Ramberg</strong> (plage la plus accessible). <strong>Activités</strong> : kayak entre les îles, escalade, pêche, randonnée Munkebu/Reinebringen. <strong>Tester</strong> bacalao, fish soup, brunost (fromage de chèvre brun). <strong>Logistique</strong> : vol Oslo-Bodø + ferry Bodø-Moskenes 4h ou avion direct Oslo-Leknes/Svolvær.",

    "macao:fr": "Macao, ancienne colonie portugaise (1557-1999), Région Administrative Spéciale de Chine depuis 1999 : 690 000 habitants sur 33 km², densité de population 4e plus forte au monde. Capitale mondiale du jeu (revenus casinos 7x supérieurs à Las Vegas avant Covid). <strong>Novembre est mon mois préféré</strong> (8.5/10) : 20-25°C, 23% de pluie, températures parfaites avant l'hiver. <strong>D'octobre à décembre</strong>, c'est la haute saison : 15-28°C, climat doux. <strong>De juin à septembre</strong>, c'est la saison chaude/humide : 65-88% de précipitations, taux d'humidité oppressant (90%), <strong>typhons fréquents</strong> (Macao subit en moyenne 5-6 par saison). <strong>De janvier à mars</strong>, comptez 15-23°C : doux mais ciel souvent gris. <strong>Sites majeurs côté patrimoine UNESCO</strong> (Centre historique 30 monuments) : <strong>Ruines de Saint-Paul</strong> (façade XVIIe, image emblématique), <strong>Largo do Senado</strong> (place pavée portugaise), <strong>Temple A-Ma</strong> (origine du nom \"Macao\" = Mât de A-Ma, Ma'Gao en chinois), <strong>Temple Na Tcha</strong>, <strong>Forteresse do Monte</strong>, <strong>Maison du Mandarin</strong>. <strong>Casinos modernes</strong> : <strong>Cotai Strip</strong> (le \"Las Vegas asiatique\" sur île gagnée sur la mer reliant Taipa et Coloane) avec <strong>Venetian Macao</strong> (le plus grand casino au monde, gondoles intérieures), <strong>City of Dreams</strong>, <strong>Wynn Palace</strong>, <strong>Grand Lisboa</strong>, <strong>MGM</strong>. <strong>Tester cuisine fusion macanaise</strong> : galinha à portuguesa (poulet au curry), porc au shrimp paste, pastéis de nata (tartes aux œufs portugaises, origine ici puis Lisbonne), almond cookies. <strong>Logistique</strong> : Macao à 1h en ferry de Hong Kong (TurboJet), vol direct depuis Bangkok/Tokyo/Manille. Visa délivré à l'arrivée pour Européens (90 jours). Pataca (MOP) liée au HKD.",

    "malte:fr": "Malte est l'État membre le plus petit de l'UE : 316 km², 540 000 habitants, 3 îles (Malte, Gozo, Comino), histoire mille fois millénaire (Phéniciens, Romains, Arabes, Normands, Chevaliers de l'Ordre de Saint-Jean 1530-1798, Britanniques 1814-1964). <strong>Juin est mon mois préféré</strong> (9.7/10) : 21-27°C, 3% de pluie, mer à 23°C, météo idéale avant la canicule. <strong>Juillet-août chutent à 6.9/10</strong> à cause de la chaleur (24-30°C) et de la <strong>foule extrême</strong> : Malte concentre 3 millions de touristes/an pour 540 000 habitants, prix hôteliers x3, plages bondées. <strong>De décembre à mars</strong>, comptez 11-17°C et 21-37% de pluie : doux pour l'Europe, climat idéal pour visiter culture sans foule, golfeurs européens en hivernage. <strong>Septembre est aussi excellent</strong> (9.1/10). <strong>Sites majeurs</strong> : <strong>La Valette</strong> (capitale UNESCO, fondée par les Chevaliers en 1566, Co-Cathédrale St-Jean avec Caravages, Palais des Grands Maîtres), <strong>Mdina</strong> (\"Cité du Silence\", ancienne capitale fortifiée), <strong>Hypogée de Hal Saflieni</strong> (UNESCO, temple souterrain 4000 ans, réservation 3 mois avant, 100 visiteurs/jour seulement), <strong>Temples mégalithiques</strong> de Hagar Qim et Mnajdra (UNESCO, 5000 ans, antérieurs aux pyramides), <strong>Marsaxlokk</strong> (port de pêche aux luzzu colorés, marché du dimanche). <strong>Gozo</strong> en ferry 25 min (île plus calme, Citadella de Victoria, Salines de Marsalforn, Dwejra Bay). <strong>Comino</strong> et son <strong>Blue Lagoon</strong> (eau turquoise, snorkeling, accessible en bateau depuis Malte/Gozo). <strong>Sliema</strong> et <strong>St. Julian's</strong> = stations balnéaires modernes. <strong>Tester</strong> pastizzi (chausson fromage/petits pois), rabbit stew (lapin local), ftira, vin Marsovin/Meridiana.",

    "martinique:fr": "La Martinique, département français d'outre-mer aux Petites Antilles : 1100 km², 360 000 habitants, l'\"île aux fleurs\" (en créole \"Madinina\"). <strong>Janvier est mon mois préféré</strong> (8.1/10) : 23-28°C, 58% de pluie, c'est le carême (saison sèche), mer à 27°C. <strong>De décembre à mai</strong>, c'est la haute saison touristique : 22-30°C, prix hôteliers x2-x3, vol depuis Paris x3 en pleine saison. <strong>De juillet à octobre</strong>, c'est la saison cyclonique active (\"hivernage\") : 70-81% de précipitations, risque ouragans réel (Maria 2017 a touché). <strong>De juin et novembre</strong> sont les meilleures intersaisons. <strong>Sites majeurs</strong> : <strong>Fort-de-France</strong> (capitale, marché aux épices), <strong>Saint-Pierre</strong> (ancienne \"Petit Paris des Antilles\", détruite par l'éruption de la <strong>Montagne Pelée</strong> le 8 mai 1902 = 30 000 morts en 1 minute, 1 seul survivant Cyparis dans son cachot, ruines visitables), <strong>Montagne Pelée</strong> (1397m, randonnée 6h aller-retour, volcan toujours actif), <strong>Trois-Îlets</strong> (maison natale de l'Impératrice Joséphine), <strong>Diamond Rock</strong> (Le Diamant, rocher iconique au sud), <strong>Pointe du Bout</strong> (zone hôtelière), <strong>Anses-d'Arlet</strong> (église signature en bord de plage), <strong>Plage des Salines</strong> (la plus connue, sud), <strong>Tartane</strong> (Caravelle, côte sauvage), <strong>Habitations</strong> Clément (rhum, ancienne plantation), Saint-James (rhum). <strong>Activités</strong> : plongée (Diamond Rock, Saint-Pierre), randonnée Canal des Esclaves, croisières Grenadines au sud (Saint-Lucie 30 min en hélicoptère). <strong>Tester</strong> accras de morue, colombo de poulet, boudin créole, ti-punch, planteur, rhum AOC Martinique (le seul AOC au monde pour le rhum). Vol direct Paris en 8h.",

    "memphis:fr": "Memphis, dans le Tennessee : 630 000 habitants, berceau du <strong>blues</strong> (Beale Street), du <strong>rock'n'roll</strong> (Sun Studio où Elvis Presley a enregistré son premier disque en 1954), et du <strong>soul</strong> (Stax Records). Aussi tristement célèbre pour l'assassinat de <strong>Martin Luther King Jr.</strong> au Lorraine Motel le 4 avril 1968. <strong>Octobre est mon mois préféré</strong> (8.5/10) : 13-24°C, 22% de pluie, températures parfaites, foliage en Tennessee, festivals (Indie Memphis Film Festival). <strong>De mai à septembre</strong>, comptez 17-33°C : chaud et humide, festivals (Memphis in May = barbecue contest mondial, Beale Street Music Festival), tornadoes possibles au printemps. <strong>De décembre à février</strong>, comptez 1-13°C et 32-41% de pluie : doux pour le sud mais grisâtre. <strong>D'avril et octobre-novembre</strong> sont les meilleures intersaisons. <strong>Sites majeurs musicaux</strong> : <strong>Graceland</strong> (la maison d'Elvis depuis 1957, mausolée familial, Trophy Building, jets, voitures - visite 4h, 80€), <strong>Sun Studio</strong> (Elvis, Johnny Cash, Jerry Lee Lewis, Carl Perkins, BB King ont tous enregistré ici, visite 30 min), <strong>Stax Museum</strong> (Otis Redding, Isaac Hayes), <strong>Beale Street</strong> (rue piétonne du blues, BB King's Blues Club, Rum Boogie Cafe), <strong>Rock and Soul Museum</strong>. <strong>Sites historiques</strong> : <strong>National Civil Rights Museum</strong> au Lorraine Motel (lieu de l'assassinat de MLK conservé tel quel, musée important sur les droits civiques aux USA). <strong>Mississippi River</strong> en cargo de croisière. <strong>Mud Island River Park</strong>. <strong>Tester</strong> Memphis BBQ (porc effiloché à la sauce sucrée vinaigrée, chez Cozy Corner ou Central BBQ, distinct de Texas/Kansas City BBQ), barbecue spaghetti chez The Bar-B-Q Shop, ribs.",

    "monaco:fr": "Monaco, principauté souveraine de 2 km² : 38 000 habitants (l'un des plus petits pays au monde), enclavé en France à la frontière italienne, dirigé par la dynastie Grimaldi depuis 1297. <strong>Juillet-août sont mes mois préférés</strong> (9.5/10) : 21-28°C, 11-14% de pluie, mer à 24°C, <strong>Grand Prix de Formule 1</strong> fin mai (le plus prestigieux du calendrier, course en circuit urbain à 290 km/h dans les rues étroites, prix hôteliers x10 pendant l'événement). <strong>De juin à septembre</strong>, c'est la haute saison touristique : 17-28°C, prix hôteliers x3-x5 toute la saison, événements (Yacht Show fin septembre, Tournoi de tennis ATP avril). <strong>De décembre à février</strong>, comptez 4-13°C et 19-25% de pluie : doux pour la France, ambiance plus paisible, prix divisés par 2. <strong>Sites majeurs</strong> : <strong>Casino de Monte-Carlo</strong> (Belle Époque, 1863, place du Casino avec Hôtel de Paris et Café de Paris, accès au casino 18€ + tenue correcte exigée), <strong>Palais Princier</strong> (relève de garde tous les jours à 11h55, appartements ouverts au public hors saison) et <strong>Cathédrale</strong> (où sont enterrés Grace Kelly et Rainier III), <strong>Musée Océanographique</strong> (Cousteau, fondé par le Prince Albert Ier, perché sur la falaise), <strong>Jardin Exotique</strong> (cactus géants, Grotte Observatoire), <strong>Jardin Japonais</strong>, <strong>Casino Café de Paris</strong> (machines à sous gratuites, ambiance plus accessible). <strong>Vieille Monaco</strong> (le \"Rocher\") avec son fort Antoine. <strong>Sport</strong> : AS Monaco football au Stade Louis II. <strong>Tester</strong> barbagiuan (chausson aux blettes), socca (galette niçoise voisine), pissaladière. <strong>Logistique</strong> : Monaco à 25 min de Nice en train (gare souterraine spectaculaire), pas d'aéroport (Nice à 25 min en hélicoptère pour 150€/personne).",

    "monterey:fr": "Monterey, en Californie : 30 000 habitants, ancienne capitale de la Californie espagnole puis mexicaine, sur la péninsule entre San Francisco (2h30 au nord) et Big Sur (1h au sud). Climat le plus stable de Californie (Mark Twain et Robert Louis Stevenson y séjournaient). <strong>Septembre est mon mois préféré</strong> (8.2/10) : 14-19°C, 3% de pluie, mer à 14-15°C (très fraîche, combinaison nécessaire pour la baignade). <strong>D'avril à octobre</strong>, c'est la haute saison touristique : 9-19°C, climat doux constant. <strong>De novembre à mars</strong>, comptez 9-19°C et 20-34% de pluie : encore doux, foules réduites. <strong>Toute l'année</strong> = climat agréable mais souvent brumeux le matin (\"June Gloom\" californien). <strong>Sites majeurs</strong> : <strong>Cannery Row</strong> (popularisée par John Steinbeck dans Rue de la Sardine 1945, ancienne rue des conserveries devenue zone touristique), <strong>Monterey Bay Aquarium</strong> (l'un des meilleurs au monde, kelp forest, otters, gigantesque tank pélagique, à réserver), <strong>Old Fisherman's Wharf</strong> (otaries omniprésentes), <strong>17-Mile Drive</strong> (route panoramique payante 12$ entre Monterey et Carmel, manoirs, Lone Cypress, Pebble Beach Golf Links), <strong>Carmel-by-the-Sea</strong> à 10 min (village d'artistes, cottages charmants, Clint Eastwood en a été maire), <strong>Point Lobos State Reserve</strong> (côte sauvage, otters, baleines en migration). <strong>Big Sur</strong> à 1h au sud (côte Pacifique la plus spectaculaire des USA, route 1, McWay Falls, pont Bixby Bridge - mais surveiller fermetures route après éboulements). <strong>Activités</strong> : whale watching (baleines grises décembre-mars, bleues juillet-août), kayak avec les otters, golf à Pebble Beach (le plus connu au monde, 600$/round). <strong>Tester</strong> clam chowder dans bread bowl, fish and chips, vin de Monterey County (Pinot Noir, Chardonnay).",

    "munich:fr": "Munich (München), capitale de Bavière : 1,5 million d'habitants, ville la plus prospère d'Allemagne (BMW, Siemens), ambiance \"Italie du Nord\" (jardins biergartens, art baroque). <strong>Juillet-août sont mes mois préférés</strong> (8.1/10) : 14-24°C, 46-48% de pluie en orages d'après-midi, biergartens pleins, festivals. <strong>L'Oktoberfest</strong> (mi-septembre à début octobre, 16 jours, 6 millions de visiteurs, 7 millions de litres de bière) = pic touristique absolu, prix x5, hôtels complets 6 mois avant, ambiance unique. <strong>De novembre à mars</strong>, comptez -2/8°C et 38-45% de précipitations souvent neige : froid sec, marché de Noël Christkindlmarkt (Marienplatz, plus de 30 marchés de Noël à Munich) du 25 novembre au 24 décembre, ski possible à 1h30 en bus (Zugspitze 2962m, Garmisch-Partenkirchen). <strong>Sites majeurs</strong> : <strong>Marienplatz</strong> (place principale, Glockenspiel 11h et 12h chaque jour - 32 personnages animés), <strong>Frauenkirche</strong> (cathédrale gothique signature avec ses 2 dômes verts), <strong>Résidence</strong> (palais des Wittelsbach pendant 700 ans), <strong>Hofbräuhaus</strong> (la brasserie la plus connue au monde depuis 1589), <strong>Englischer Garten</strong> (le plus grand parc urbain d'Europe, plus grand que Central Park, vague de surf permanente sur l'Eisbach, biergartens, Chinesischer Turm), <strong>Viktualienmarkt</strong> (marché central permanent), <strong>BMW Welt et Museum</strong>. <strong>Excursions</strong> : <strong>Château de Neuschwanstein</strong> à 2h (Louis II, château signature de Disney, à réserver), <strong>Dachau</strong> à 30 min (1er camp de concentration nazi, mémorial, gratuit), <strong>Salzbourg</strong> à 1h30, <strong>Innsbruck</strong> à 2h. <strong>Tester</strong> Wiener Schnitzel, Weisswurst (saucisse blanche, à manger avant midi tradition), Brezen (bretzel), Schweinshaxe (jarret de porc), bière (Augustiner, Hacker-Pschorr, Spaten).",

    "napa-valley:fr": "Napa Valley, en Californie : la région viticole la plus prestigieuse des USA, 80 km au nord de San Francisco, 3 vallées parallèles (Napa, Sonoma, Russian River), 400+ caves. <strong>Juin est mon mois préféré</strong> (9.7/10) : 13-30°C, 2% de pluie, températures idéales avant la canicule estivale. <strong>De mai à octobre</strong>, c'est la haute saison touristique : 10-33°C, 0-11% de pluie. <strong>Septembre-octobre</strong> = saison des vendanges (\"crush\"), animation maximale dans les caves, mais aussi <strong>saison des incendies</strong> de plus en plus fréquente depuis 2017 (incendies majeurs Atlas Fire 2017, Glass Fire 2020 ont brûlé des wineries entières). <strong>De novembre à mars</strong>, comptez 5-17°C et 11-35% de pluie : période plus calme, prix hôteliers réduits, dégustations sans foule, paysages verdoyants. <strong>Sites majeurs</strong> : <strong>Domaines à visiter</strong> : Castello di Amorosa (réplique de château italien, kitsch mais photogénique), Robert Mondavi (le pionnier moderne de Napa, mort en 2008), Opus One (joint Mondavi-Rothschild, prestige), Far Niente, Domaine Carneros (mousseux), Sterling Vineyards (téléphérique pour atteindre la cave), Beringer (la plus ancienne, 1876). <strong>Cabernet Sauvignon</strong> = le cépage roi de Napa (60% de la production), Chardonnay et Pinot Noir au sud (Carneros plus frais). <strong>Réservation obligatoire</strong> pour les dégustations (50-200$/personne, parfois plus pour les vins cultes Screaming Eagle, Harlan, Scarecrow). <strong>Activités</strong> : <strong>Napa Valley Wine Train</strong> (train gastronomique 3-6h, 200-500$/personne), montgolfière au lever du soleil (400€), spa à Calistoga (sources géothermales, mud baths). <strong>Yountville</strong> = village gastronomique (French Laundry de Thomas Keller, restaurant 3*** Michelin parmi les plus prestigieux des USA, 425$ menu). À 1h30 de San Francisco.",

    "normandie:fr": "La Normandie, c'est l'ouest de la France : 30 000 km², 3,3 millions d'habitants, 600 km de côtes, falaises, plages du Débarquement (1944), camembert et calvados. <strong>Juillet-août sont mes mois préférés</strong> (8.3-8.4/10) : 14-23°C, 33% de pluie, températures clémentes. <strong>De juin à septembre</strong>, c'est la haute saison : 13-22°C, mais météo capricieuse (Normandie pluvieuse mais souvent ensoleillée, alternance rapide). <strong>De novembre à mars</strong>, comptez 5-13°C et 41-45% de pluie : océanique humide, ciel souvent gris, beaucoup de stations balnéaires en sommeil. <strong>Sites majeurs</strong> : <strong>Mont-Saint-Michel</strong> (UNESCO, l'un des sites les plus visités de France, marées les plus fortes d'Europe ±15m, à voir la nuit ou en marée haute, parking obligatoire à 2,5 km + navette ou marche), <strong>Plages du Débarquement</strong> (Omaha Beach, Utah Beach, Juno, Gold, Sword, Pointe du Hoc - cimetières américain et britannique, Mémorial de Caen), <strong>Bayeux</strong> (Tapisserie du XIe siècle racontant la conquête de l'Angleterre par Guillaume le Conquérant en 1066, UNESCO, 70m de long), <strong>Etretat</strong> (falaises d'Aval-Manneporte-Amont, peintes par Monet, surfréquentée en saison), <strong>Honfleur</strong> (port pittoresque, peint par Monet et Boudin), <strong>Deauville-Trouville</strong> (stations balnéaires chics du XIXe, Festival du Cinéma Américain en septembre), <strong>Rouen</strong> (cathédrale gothique peinte 30 fois par Monet, lieu d'exécution de Jeanne d'Arc), <strong>Giverny</strong> (maison et jardins de Claude Monet, à voir d'avril à octobre). <strong>Iles Anglo-Normandes</strong> (Jersey, Guernesey) en ferry depuis Saint-Malo voisin. <strong>Tester</strong> camembert, livarot, Pont-l'Évêque (3 fromages AOC), tarte normande, andouille de Vire, calvados, cidre, teurgoule. Mai-juin et septembre = meilleurs compromis.",

    "palm-springs:fr": "Palm Springs, en Californie : 45 000 habitants à 200 km à l'est de Los Angeles, station thermale-resort dans le désert de Sonora au pied des montagnes San Jacinto (3300m). Repaire historique des stars hollywoodiennes des 50s-60s (Sinatra, Presley, Marilyn). Capitale mondiale de l'architecture <strong>Mid-Century Modern</strong>. <strong>Avril est mon mois préféré</strong> (9.3/10) : 16-30°C, 5% de pluie, températures idéales, festival <strong>Coachella</strong> (à 40 min, 2 weekends mi-avril, l'un des plus grands festivals musique au monde, 250 000 personnes, prix hôteliers x10). <strong>D'octobre à mai</strong>, c'est la haute saison \"snowbird\" : 9-31°C, 3-12% de pluie, climat sec idéal, golfs en pleine activité (130 parcours dans la Coachella Valley = densité golf record au monde). <strong>De juin à août chutent à 3.9/10</strong> à cause de la chaleur extrême (24-41°C, parfois 49°C en juillet, l'une des villes les plus chaudes des USA), prix hôteliers divisés par 2-3. <strong>Sites majeurs</strong> : <strong>Aerial Tramway</strong> (téléphérique rotatif, l'un des plus longs au monde, 800 → 2596m sur Mount San Jacinto en 10 min, 30°C de différence en bas et en haut, randonnée et neige en hiver), <strong>Joshua Tree National Park</strong> à 45 min (paysages martiens, arbres yucca signatures, U2 album cover), <strong>Sunnylands</strong> (résidence Annenberg ex-Camp David de la côte Ouest), <strong>Architecture Mid-Century</strong> (Modernism Week en février = l'événement de référence, visites de maisons Sinatra, Kaufmann House de Richard Neutra). <strong>Sonny Bono Memorial</strong>. <strong>Coachella Valley Preserve</strong>, <strong>Indian Canyons</strong> (oasis de palmiers en plein désert). <strong>Tester</strong> les dattes locales (Coachella Valley = capitale US de la datte), date shake (signature locale), fish tacos. Vol direct depuis Paris vers LAX puis 2h de route.",

    "plitvice:fr": "Le parc national de Plitvice, en Croatie : 295 km², classé UNESCO depuis 1979, l'un des plus beaux parcs naturels d'Europe. <strong>16 lacs en cascade</strong> reliés par des chutes d'eau (90 cascades total), couleur turquoise extraordinaire due aux dépôts de calcaire et de minéraux. <strong>Juillet-août sont mes mois préférés</strong> (8.7-8.8/10) : 16-26°C, 30-34% de pluie, températures parfaites pour les sentiers en bois (15 km au total, plusieurs circuits A à K de 2h à 8h). <strong>De juin à septembre</strong>, c'est la haute saison : 12-26°C, mais aussi <strong>foule extrême</strong> : Plitvice reçoit 1,8 million de visiteurs/an, parking saturé en milieu de matinée, sentiers congestionnés (en particulier autour de Veliki Slap = la grande cascade 78m). Réservation obligatoire des billets en ligne depuis 2020 avec créneaux horaires. <strong>De novembre à mars</strong>, comptez 0-10°C et 33-48% de pluie ou neige : <strong>Plitvice sous la neige</strong> est <strong>spectaculaire</strong> (cascades partiellement gelées, sentiers déserts), prix divisés par 2, certains sentiers fermés pour sécurité. <strong>Sites majeurs</strong> : <strong>Veliki Slap</strong> (78m, plus haute cascade de Croatie), <strong>Lacs Inférieurs</strong> (Donji Jezera, calcaire dépôts spectaculaires, accès par sentier le plus photogénique), <strong>Lacs Supérieurs</strong> (Gornji Jezera, les plus grands), <strong>Bateaux électriques</strong> sur le lac Kozjak (les seuls bateaux autorisés, gratuits avec billet d'entrée). <strong>Sentiers en bois</strong> entièrement sur pilotis au-dessus de l'eau (sensation de marcher sur l'eau). <strong>Logistique</strong> : entrée 35€ (haute saison) ou 10€ (basse saison). 2-3h minimum pour le circuit court, 6-8h pour le circuit complet (A,B,C,E,F,K). <strong>Hôtels Jezero/Plitvice/Bellevue</strong> dans le parc (réservation 6 mois avant). À 2h en voiture de Zagreb, 2h30 de Zadar, 3h30 de Dubrovnik. <strong>Krka National Park</strong> (alternative ou complément à 2h, baignade autorisée à Skradinski Buk).",

    "quebec-ville:fr": "Québec, capitale de la province de Québec (Canada) : 540 000 habitants, fondée en 1608 par Champlain, seule ville fortifiée d'Amérique du Nord au nord du Mexique (UNESCO 1985). 95% francophone (différence majeure avec Montréal plus bilingue). <strong>Juin-août sont mes mois préférés</strong> (8.0/10) : 6-25°C, 41-53% de pluie, températures clémentes après le long hiver, festivals (Festival d'été de Québec mi-juillet, l'un des plus grands au Canada). <strong>De septembre à octobre</strong>, c'est le <strong>foliage spectaculaire</strong> : 5-20°C, érables rouges, l'une des plus belles régions au monde pour cette saison. <strong>De décembre à mars</strong>, comptez -14/0°C et 37-46% de précipitations (souvent neige abondante, Québec reçoit 3m de neige/an) : c'est le <strong>Carnaval de Québec</strong> (fin janvier-mi-février, 3 semaines, le plus grand carnaval d'hiver au monde, défilés Bonhomme Carnaval, courses canoës sur le Saint-Laurent gelé), <strong>Hôtel de Glace</strong> (à 30 min, hôtel reconstruit chaque hiver depuis 2001, possibilité d'y dormir), patinage sur la rivière Saint-Charles. <strong>Sites majeurs</strong> : <strong>Vieux-Québec</strong> (UNESCO, divisé en Haute-Ville sur Cap-Diamant et Basse-Ville en bord de fleuve), <strong>Château Frontenac</strong> (1893, hôtel Fairmont signature de la skyline, l'hôtel le plus photographié au monde selon certains classements), <strong>Plaines d'Abraham</strong> (1759, défaite française face aux Britanniques, fin de la Nouvelle-France), <strong>Citadelle</strong> (encore en service, relève de garde quotidienne), <strong>Place Royale</strong> et <strong>Quartier Petit-Champlain</strong> (la plus vieille rue commerçante d'Amérique du Nord), <strong>Fortifications</strong> (4,6 km de remparts intacts, à parcourir à pied). <strong>Excursions</strong> : <strong>Chute Montmorency</strong> à 15 min (84m, plus haute que Niagara), <strong>Île d'Orléans</strong> (campagne agricole), <strong>Charlevoix</strong> à 1h30. <strong>Tester</strong> poutine, tourtière, sirop d'érable, cipaille.",

    "saint-barthelemy:fr": "Saint-Barthélemy (\"Saint-Barth\" ou \"St. Barts\" en anglais), collectivité française d'outre-mer aux Petites Antilles : 25 km², 10 000 habitants, l'une des destinations les plus chic et chères des Caraïbes (la \"Saint-Tropez tropicale\"). <strong>Mars est mon mois préféré</strong> (8.7/10) : 24-25°C, 25% de pluie, mer à 26°C, fin de la haute saison. <strong>De décembre à avril</strong>, c'est la haute saison touristique : 24-26°C, 25-42% de pluie, prix hôteliers extrêmes (Hôtel Manapany ou Cheval Blanc Saint-Barth 1500-5000€/nuit, villas privées 5000-50 000€/semaine), réservations 1 an avant pour Noël/Nouvel An (où le yacht de Bezos/Murdoch et les Russes accostent à Gustavia, paparazzi à l'affût). <strong>De juin à novembre</strong>, c'est la saison cyclonique : 35-59% de précipitations, risque ouragans réel (Irma 2017 catégorie 5 a dévasté l'île à 70%), beaucoup d'hôtels ferment septembre-octobre. <strong>Sites majeurs</strong> : <strong>Gustavia</strong> (capitale, port à yachts, ancienne colonie suédoise 1784-1878 = nom français/influence scandinave dans l'architecture, boutiques luxe Hermès/Cartier/Vuitton), <strong>Plages</strong> : <strong>Saline</strong> (sauvage, pas d'aménagement), <strong>Gouverneur</strong> (sauvage), <strong>Saint-Jean</strong> (animée avec Eden Rock, hôtel iconique, atterrissage spectaculaire des avions juste au-dessus), <strong>Anse Colombier</strong> (accessible uniquement à pied 30 min ou bateau, plage calme), <strong>Shell Beach</strong> (coquillages, en plein Gustavia), <strong>Lorient</strong> (surf), <strong>Flamands</strong>. <strong>Atterrissage à St. Jean</strong> = l'un des plus dangereux au monde (piste 650m, descente abrupte au-dessus du col de la Tourmente). <strong>Tester</strong> langouste grillée, accras, ti-punch. Vol depuis Saint-Martin (10 min en avion) après vol direct Paris-Saint-Martin.",

    "savannah:fr": "Savannah, en Géorgie : 145 000 habitants, fondée en 1733 par James Oglethorpe (1ère ville géorgienne planifiée selon plan en damier), plus belle ville coloniale du sud des USA selon de nombreux classements, <strong>22 squares ombragés</strong> (places carrées arborées) qui structurent le centre historique. <strong>Avril est mon mois préféré</strong> (8.7/10) : 15-25°C, 25% de pluie, fin du printemps avec azalées et magnolias en pleine floraison, fameux <strong>chênes de Virginie couverts de mousse espagnole</strong> (Tillandsia usneoides) qui pendent des branches. <strong>De mars à mai et octobre-novembre</strong> sont les meilleures saisons : 11-26°C, climat doux. <strong>De juin à septembre</strong>, c'est la saison cyclonique avec chaleur lourde : 44-72% de précipitations, taux d'humidité oppressant, risque ouragans réel. <strong>De décembre à février</strong>, comptez 8-21°C et 27-30% de pluie : doux pour le sud, parfait pour visites. <strong>Sites majeurs</strong> : <strong>Forsyth Park</strong> (parc central, fontaine signature 1858, pique-nique sous chênes), <strong>Cathedral Basilica of St. John the Baptist</strong> (gothique français, vitraux), <strong>SCAD Museum of Art</strong> (art contemporain dans ancien dépôt ferroviaire), <strong>Mercer-Williams House</strong> (théâtre du roman/film <strong>Minuit dans le jardin du bien et du mal</strong> de John Berendt 1994/Clint Eastwood 1997 = Savannah a explosé touristiquement après ce livre culte), <strong>Bonaventure Cemetery</strong> (cimetière à 10 min en bord de Wilmington River, atmosphère gothique sudiste, popularisé par le même livre), <strong>Wormsloe Historic Site</strong> (allée de chênes mythique 2,4 km, point Instagram). <strong>River Street</strong> et <strong>City Market</strong> (zones touristiques en bord de Savannah River), <strong>Tybee Island</strong> à 30 min (plage). <strong>Tester</strong> shrimp and grits, fried chicken (chez The Olde Pink House), pralines (Leopold's Ice Cream). À 2h de Charleston en voiture (on peut combiner les 2 villes en road trip Lowcountry).",

    "sedona:fr": "Sedona, en Arizona : 10 000 habitants à 1370m d'altitude au cœur des <strong>Red Rocks</strong> (formations rocheuses de grès rouge sculptées par l'érosion sur 70 millions d'années). Réputée pour ses <strong>vortex énergétiques</strong> (4 sites prétendument chargés d'énergie spirituelle, nombreux centres de retraites New Age depuis les 80s). <strong>Mai est mon mois préféré</strong> (9.6/10) : 12-27°C, 8% de pluie, températures parfaites avant la chaleur estivale. <strong>D'octobre à novembre</strong>, comptez 5-23°C avec 11-14% de pluie : excellente période, foliage doré contrastant avec les rouches rouges. <strong>De juin à août</strong>, comptez 18-34°C : chaud (parfois 40°C+) mais altitude 1370m = supportable, orages d'après-midi fréquents (\"monsoon season\" juillet-août, foudre dangereuse en randonnée). <strong>De décembre à février</strong>, comptez 0-13°C : doux le jour, gel la nuit, neige possible sur les sommets, ambiance hivernale spectaculaire (Red Rocks sous la neige). <strong>Sites majeurs</strong> : <strong>Cathedral Rock</strong> (formation iconique, randonnée 2h aller-retour, vortex spot), <strong>Bell Rock</strong> (vortex le plus accessible), <strong>Boynton Canyon</strong> (vortex et randonnées, l'un des plus beaux), <strong>Devil's Bridge</strong> (arche naturelle accessible par randonnée 6 km, point Instagram), <strong>Chapel of the Holy Cross</strong> (chapelle moderne 1956 construite dans la falaise, vue spectaculaire), <strong>Slide Rock State Park</strong> (toboggan naturel dans Oak Creek). <strong>Routes panoramiques</strong> : <strong>Red Rock Scenic Byway</strong> (route 179 entre Sedona et Village of Oak Creek), <strong>Oak Creek Canyon</strong> (route 89A vers Flagstaff au nord, l'une des plus belles routes des USA). <strong>Excursions</strong> : <strong>Grand Canyon South Rim</strong> à 2h, <strong>Antelope Canyon</strong> à 3h, <strong>Monument Valley</strong> à 4h. <strong>Activités</strong> : Pink Jeep Tour off-road sur les pistes (90 min, 100$), spas et retraites New Age, observation des étoiles (Sedona Dark Sky Park).",

    "split:fr": "Split, deuxième ville de Croatie : 180 000 habitants, ville fondée autour du <strong>Palais de Dioclétien</strong> (UNESCO), résidence construite par l'empereur romain en 305 ap JC, encore habitée 1700 ans plus tard (3000 personnes y vivent toujours). Base pour les îles dalmates (Hvar, Brač, Vis). <strong>Juin est mon mois préféré</strong> (9.4/10) : 19-28°C, 21% de pluie, mer à 23°C, températures parfaites. <strong>Juillet</strong> reste excellent (9.3/10) avec foule. <strong>Août chute à 6.9/10</strong> à cause de la chaleur (22-31°C) et de la <strong>foule extrême</strong>, prix hôteliers x4. <strong>De novembre à mars</strong>, comptez 4-13°C et 35-47% de pluie : doux pour l'Adriatique, mais beaucoup d'hôtels et restos en sommeil. <strong>D'avril-mai et septembre-octobre</strong> sont les meilleurs compromis. <strong>Sites majeurs</strong> : <strong>Palais de Dioclétien</strong> (UNESCO, plus grand monument romain conservé, palais de retraite de l'empereur, Cathédrale Saint-Domnius construite dans son ancien mausolée, péristyle, sous-sols romains visitables où les scènes de Game of Thrones ont été tournées), <strong>Riva</strong> (promenade en bord de mer, palmiers, terrasses), <strong>Marjan Hill</strong> (poumon vert avec vue panoramique sur la ville et les îles), <strong>Vieux marché Pjaca</strong>, <strong>Quartier Varoš</strong> (vieux quartier traditionnel). <strong>Excursions</strong> : <strong>Trogir</strong> à 30 min (UNESCO, ville médiévale fortifiée), <strong>Klis Fortress</strong> à 20 min (Game of Thrones, Meereen), <strong>Salona</strong> ruines romaines, <strong>Krka National Park</strong> à 1h30 (cascades, baignade autorisée à Skradinski Buk), <strong>îles dalmates</strong> en ferry ou catamaran (Hvar 1h, Brač 1h pour Bol et Zlatni Rat, Vis 2h30 - île la plus authentique, Blue Cave grotte bleue à Biševo, Mamma Mia 2 tourné ici). <strong>Tester</strong> peka, pasticada, pršut, vin Plavac Mali. Aéroport direct depuis Paris en 2h45.",

    "tromso:fr": "Tromsø, ville norvégienne au-delà du cercle polaire : 80 000 habitants à 350 km au nord du cercle polaire, plus grande ville à cette latitude au monde. Surnommée la \"Paris du Nord\" au XIXe pour son raffinement face aux explorateurs polaires (Amundsen, Nansen ont été basés ici). <strong>Juillet est mon mois préféré</strong> (7.1/10) : 10-17°C, 47% de pluie, c'est le <strong>soleil de minuit</strong> (du 18 mai au 27 juillet, pas de coucher du soleil pendant 2 mois), randonnée, pêche, observation des baleines (orques en novembre-janvier dans les fjords voisins). <strong>De juin à août</strong>, comptez 7-17°C : haute saison estivale. <strong>De novembre à mars</strong>, comptez -8/-1°C et 50-55% de précipitations souvent neige : c'est la haute saison touristique pour les <strong>aurores boréales</strong> (Tromsø est sur l'\"aurora belt\", visibles 200 nuits/an quand ciel dégagé), <strong>nuit polaire</strong> du 27 novembre au 15 janvier (pas de soleil au-dessus de l'horizon, mais lumière bleue magnifique 4-5h par jour). Prix hôteliers x3 en haute saison hivernale. <strong>Sites majeurs</strong> : <strong>Cathédrale arctique</strong> (Ishavskatedralen, 1965, architecture moderne signature visible de la ville), <strong>Téléphérique Fjellheisen</strong> (Storsteinen 421m, panorama sur la ville et les îles, 4 min de montée), <strong>Polaria</strong> (musée polaire, phoques), <strong>Polar Museum</strong> (histoire des explorations Amundsen, expéditions au pôle), <strong>Tromsø Bibliothek</strong> (architecture moderne). <strong>Activités</strong> : <strong>chasse aux aurores boréales</strong> en bus ou minivan (3-5h, 100-200€), <strong>traîneau à chiens husky</strong> (initiation 2h ou expédition 1-7 jours), <strong>safari aux baleines</strong> (depuis Skjervøy en novembre-janvier, orques et baleines à bosse), <strong>nuit en cabane samie</strong>, <strong>raquettes</strong>, <strong>ski</strong> à Tromsø Alpinpark. <strong>Tester</strong> bidos (ragoût de renne, plat sami), saumon, baleine (controversé). Vol direct Oslo en 2h.",

    "yellowstone:fr": "Yellowstone, le 1er parc national au monde (créé 1872) : 9000 km² au Wyoming-Montana-Idaho (USA), assis sur un super-volcan dormant, paysages géothermiques uniques (geysers, sources chaudes colorées, fumerolles). <strong>Juillet est mon mois préféré</strong> (8.8/10) : 8-22°C, 28% de pluie, c'est la haute saison touristique (4 millions de visiteurs/an, 70% en juin-août), routes intérieures toutes ouvertes, faune visible (bisons, élans, ours, loups). <strong>D'août</strong> reste excellent (8.3/10). <strong>De juin à septembre</strong>, c'est la haute saison : 3-22°C, mais aussi <strong>foules extrêmes</strong> aux principaux sites (Old Faithful saturé, embouteillages 1-2h pour voir les ours), <strong>réservation hôtels 1 an avant</strong> pour les lodges historiques (Old Faithful Inn, Lake Yellowstone Hotel). <strong>De novembre à mars</strong>, comptez -12/-1°C et 37-50% de précipitations souvent neige : <strong>Yellowstone en hiver</strong> est <strong>spectaculaire</strong> (tout est blanc, très peu de touristes, faune visible plus facilement, ciel souvent dégagé), mais <strong>routes intérieures fermées</strong> sauf Mammoth-Cooke City accessible toute l'année + tour en snowcoach ou motoneige obligatoire pour explorer. <strong>D'avril à mai et septembre-octobre</strong> sont les transitions (printemps tardif, automne court). <strong>Sites majeurs</strong> : <strong>Old Faithful</strong> (geyser le plus connu, éruption toutes les 90 min ±10 min, 30-55m de hauteur), <strong>Grand Prismatic Spring</strong> (source chaude de 110m de diamètre, couleurs spectaculaires, point de vue Fairy Falls Trail à 800m de marche), <strong>Mammoth Hot Springs</strong> (terrasses calcaires blanches), <strong>Grand Canyon of the Yellowstone</strong> (Lower Falls 94m), <strong>Lamar Valley</strong> (\"Serengeti américain\" pour la faune, lever du soleil ou coucher), <strong>Hayden Valley</strong> (bisons), <strong>Lake Yellowstone</strong> (lac alpin le plus grand des USA). <strong>Sécurité</strong> : <strong>ours noirs et grizzlys</strong> nombreux (bear spray obligatoire pour les randos arrière-pays), bisons agressifs (rester à 25m). <strong>Tester</strong> bison burger. <strong>Logistique</strong> : aéroport le plus proche Bozeman (Montana, 90 min de West Entrance) ou Jackson Hole (Wyoming, 1h de South Entrance).",

    "zanzibar:fr": "Zanzibar, archipel tanzanien dans l'océan Indien : 2 îles principales (Unguja la plus grande appelée par confusion \"Zanzibar\", et Pemba), 1,3 million d'habitants, mélange culturel afro-arabe (sultanat d'Oman 1698-1856), capitale historique du commerce d'esclaves et d'épices. <strong>Juillet-août sont mes mois préférés</strong> (8.3/10) : 22-28°C, 50-51% de pluie, c'est la \"saison sèche\" (kusi vent du sud-est). <strong>De juin à octobre</strong>, c'est la haute saison touristique : 22-30°C, 50-59% de précipitations en averses brèves, mer à 26°C. <strong>De mars à mai</strong>, c'est la <strong>longue saison des pluies</strong> (\"masika\") : 67-92% de précipitations, beaucoup d'hôtels ferment, mer agitée. <strong>De novembre à février</strong>, c'est la \"saison chaude\" (kaskazi vent du nord-est) : 24-32°C, 41-75% de précipitations en averses brèves d'après-midi, mer à 28°C, plus chaude pour la baignade. <strong>Sites majeurs</strong> : <strong>Stone Town</strong> (UNESCO, capitale, dédale de ruelles, portes en bois sculptées caractéristiques 800 portes recensées, Maison des Merveilles, ancien marché aux esclaves devenu cathédrale anglicane mémorial Slave Market), <strong>Forodhani Gardens</strong> (marché nocturne tous les soirs, brochettes, soupes), <strong>Spice Tour</strong> (à 30 min, plantations de clou de girofle/cardamome/vanille/cannelle, Zanzibar reste le plus grand exportateur mondial de clou de girofle). <strong>Plages côté est</strong> (les plus belles, mais marées importantes ±3m qui découvrent 1 km de sable à marée basse) : <strong>Paje</strong> (kitesurf), <strong>Jambiani</strong> (tranquille), <strong>Pingwe</strong>. <strong>Plages côté nord</strong> (sans effet marée, idéales pour la baignade) : <strong>Nungwi</strong> (animée), <strong>Kendwa</strong> (Full Moon Party). <strong>Activités</strong> : nage avec tortues à <strong>Mnemba Atoll</strong>, plongée sur Mnemba Reef, observation des dauphins à Kizimkazi. <strong>Tester</strong> Zanzibar pizza (street food local), pilau aux épices, octopus curry. <strong>Logistique</strong> : Zanzibar à 1h30 de Dar es Salaam en ferry + 30 min en avion (vol direct Paris ou via Doha/Istanbul)."
}

with open(PATH, encoding='utf-8') as f:
    data_existing = json.load(f)

before = len([k for k in data_existing if k.endswith(':fr') and not k.startswith('_')])

data_existing['_version'] = '2.3'
data_existing['_updated'] = '2026-04-28'

for k, v in AVIS_BATCH12_FR.items():
    data_existing[k] = v

after = len([k for k in data_existing if k.endswith(':fr') and not k.startswith('_')])

with open(PATH, 'w', encoding='utf-8') as f:
    json.dump(data_existing, f, ensure_ascii=False, indent=2)

print(f"Avis FR avant : {before}")
print(f"Avis FR après : {after}")
print(f"Nouveaux : {after - before}")

# Audit immédiat
import re
patterns_check = [
    ('em-dash', r'—'), ('guillemets', r'[«»]'),
    ('attendez-vous', r'attendez-vous à'),
    ('parfait', r'\bparfait[es]*\b'),
    ('fenêtre', r'\bfenêtre[s]?\b'),
    ('saturé', r'\bsatur[eéa]\w*\b'),
    ('se mérite', r'\bse méri[tes]+\b'),
    ('magique', r'\bmagiques?\b'),
    ('Si vous X:', r'Si vous \w+ : '),
    ('iconique', r'\biconique[s]?\b'),
    ('antithèse', r'antithèse'),
    ('mythique', r'\bmythique[s]?\b'),
    ('emblématique', r'\bemblématique[s]?\b'),
    ('authentique', r'\bauthentique[s]?\b'),
    ('féérique', r'\bféérique[s]?\b'),
    ("c'est aussi", r"[Cc]'est aussi"),
    ('à monitorer', r'à monitorer'),
    ('à éviter', r'à éviter'),
]

print("\n=== Audit batch 12 ===")
issues_total = 0
for slug in AVIS_BATCH12_FR.keys():
    plain = re.sub(r'<[^>]+>', '', data_existing[slug])
    issues = []
    for label, p in patterns_check:
        n = len(re.findall(p, plain))
        if n > 0:
            issues.append(f"{label}={n}")
            issues_total += n
    flag = "OK" if not issues else "PB " + ", ".join(issues)
    print(f"  {slug:<22} {len(plain.split()):>3}m {flag}")
print(f"\nTotal issues : {issues_total}")
